import React, { useState } from "react";
import { submitFeedback } from "../../services/api";

export default function FeedbackForm() {
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setMessage("");

    try {
      await submitFeedback(Number(rating), comment.trim());
      setComment("");
      setRating(5);
      setMessage("Feedback submitted successfully.");
    } catch (error) {
      setMessage(error.message || "Failed to submit feedback.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="p-4 bg-white rounded shadow mt-5 max-w-xl mx-auto">
      <h2 className="text-xl font-bold mb-3">Give Your Feedback</h2>

      <form onSubmit={submit}>
        <select
          className="border p-2 rounded w-full mb-3"
          value={rating}
          onChange={(e) => setRating(e.target.value)}
        >
          {[5,4,3,2,1].map(r => <option key={r}>{r}</option>)}
        </select>

        <textarea
          placeholder="Write your comment..."
          className="border p-2 rounded w-full mb-3"
          value={comment}
          onChange={(e) => setComment(e.target.value)}
        />

        <button
          className="bg-red-600 text-white px-4 py-2 rounded disabled:opacity-70"
          disabled={isSubmitting}
        >
          {isSubmitting ? "Submitting..." : "Submit"}
        </button>
      </form>

      {message && <p className="mt-3 text-sm text-gray-600">{message}</p>}
    </div>
  );
}
